command:
$ErrorActionPreference = 'Stop'
$repo = 'malwaredevil/dcoir-collector'
$requestId = 'exec-20260603-issue197-label-migration-dry-run-001'
$repoRoot = [Environment]::GetEnvironmentVariable('DCOIR_REPO_ROOT','Machine')
if ([string]::IsNullOrWhiteSpace($repoRoot)) { $repoRoot = (Get-Location).Path }
$token = [Environment]::GetEnvironmentVariable('DCOIR_GITHUB_FG_TOKEN','Machine')
if ([string]::IsNullOrWhiteSpace($token)) { $token = [Environment]::GetEnvironmentVariable('DCOIR_GITHUB_CL_TOKEN','Machine') }
if ([string]::IsNullOrWhiteSpace($token)) { throw 'No DCOIR_GITHUB_FG_TOKEN or DCOIR_GITHUB_CL_TOKEN available in Machine environment.' }
$headers = @{ Authorization = "Bearer $token"; Accept = 'application/vnd.github+json'; 'X-GitHub-Api-Version' = '2022-11-28' }
function Get-Paged { param([string]$Uri) $all=@(); $page=1; while ($true) { $sep=if($Uri.Contains('?')){'&'}else{'?'}; $u="$Uri${sep}per_page=100&page=$page"; $b=Invoke-RestMethod -Method Get -Uri $u -Headers $headers; if($null -eq $b -or @($b).Count -eq 0){break}; $all+=@($b); if(@($b).Count -lt 100){break}; $page++ }; return $all }
$renameMap = [ordered]@{ 'area:airtable-ircore' = 'area:supabase-ircore'; 'area:gemini' = 'area:gemini-agent' }
$labels = Get-Paged "https://api.github.com/repos/$repo/labels"
$issues = Get-Paged "https://api.github.com/repos/$repo/issues?state=all"
$labelNames = @($labels | ForEach-Object { [string]$_.name })
$renameTargets = @($renameMap.Values)
$createCandidates = @($renameTargets | Where-Object { $labelNames -notcontains $_ })
$keepLabels = @($labelNames | Where-Object { (($_ -like 'area:*') -or ($_ -like 'type:*')) -and -not $renameMap.Contains($_) }) + $createCandidates
$deleteLabels = @($labelNames | Where-Object { (-not (($_ -like 'area:*') -or ($_ -like 'type:*'))) -or $renameMap.Contains($_) })
function Infer-Area { param([string[]]$Names)
  if($Names -contains 'gemini-agent' -or $Names -contains 'area:gemini'){ return 'area:gemini-agent' }
  if($Names -contains 'ircore' -or $Names -contains 'area:airtable-ircore'){ return 'area:supabase-ircore' }
  if($Names -contains 'dependencies' -or $Names -contains 'github-actions' -or $Names -contains 'github_actions'){ return 'area:github-repo' }
  if($Names -contains 'documentation' -or $Names -contains 'track:docs'){ return 'area:docs' }
  if($Names -contains 'track:workflow'){ return 'area:workflows' }
  if($Names -contains 'track:collector'){ return 'area:collector' }
  if($Names -contains 'track:validation'){ return 'area:validation' }
  if($Names -contains 'track:skills'){ return 'area:operator-tooling' }
  if($Names -contains 'track:research'){ return 'area:repo-governance' }
  if($Names -contains 'track:governance' -or $Names -contains 'governance' -or $Names -contains 'governance-cleanup' -or $Names -contains 'agent-instructions' -or $Names -contains 'administrative' -or $Names -contains 'architecture' -or $Names -contains 'mirror' -or $Names -contains 'source:airtable-work-item' -or $Names -contains 'source:airtable-idea' -or $Names -contains 'source:governed-repo' -or $Names -contains 'source:mirror-initiative' -or $Names -contains 'codex'){ return 'area:repo-governance' }
  return $null
}
function Infer-Type { param([string[]]$Names)
  if($Names -contains 'bug'){ return 'type:bug' }
  if($Names -contains 'enhancement'){ return 'type:enhancement' }
  if($Names -contains 'dependencies' -or $Names -contains 'documentation' -or $Names -contains 'github-actions' -or $Names -contains 'github_actions'){ return 'type:maintenance' }
  if($Names -contains 'source:airtable-idea' -or $Names -contains 'question'){ return 'type:idea' }
  if($Names -contains 'governance-cleanup' -or $Names -contains 'track:automation'){ return 'type:cleanup' }
  if($Names -contains 'architecture' -or $Names -contains 'governance' -or $Names -contains 'agent-instructions' -or $Names -contains 'administrative' -or $Names -contains 'mirror' -or $Names -contains 'source:airtable-work-item' -or $Names -contains 'source:governed-repo' -or $Names -contains 'source:mirror-initiative' -or $Names -contains 'track:governance' -or $Names -contains 'track:research' -or $Names -contains 'codex'){ return 'type:maintenance' }
  return $null
}
$plans = foreach($item in $issues){
  $orig = @($item.labels | ForEach-Object { [string]$_.name })
  $proposed = New-Object System.Collections.Generic.List[string]
  foreach($name in $orig){ if($renameMap.Contains($name)){ [void]$proposed.Add($renameMap[$name]) } elseif($keepLabels -contains $name){ [void]$proposed.Add($name) } }
  $proposed = @($proposed | Select-Object -Unique)
  $areas = @($proposed | Where-Object { $_ -like 'area:*' })
  $types = @($proposed | Where-Object { $_ -like 'type:*' })
  if(@($areas).Count -eq 0){ $a=Infer-Area $orig; if($a){ $proposed += $a } }
  if(@($types).Count -eq 0){ $t=Infer-Type $orig; if($t){ $proposed += $t } }
  $proposed = @($proposed | Select-Object -Unique)
  $areas = @($proposed | Where-Object { $_ -like 'area:*' })
  $types = @($proposed | Where-Object { $_ -like 'type:*' })
  $remove = @($orig | Where-Object { $proposed -notcontains $_ })
  $add = @($proposed | Where-Object { $orig -notcontains $_ })
  $warnings = @()
  if(@($areas).Count -ne 1){ $warnings += "expected exactly one area label after migration; got $(@($areas).Count)" }
  if(@($types).Count -ne 1){ $warnings += "expected exactly one type label after migration; got $(@($types).Count)" }
  $hasDelete = @($orig | Where-Object { $deleteLabels -contains $_ }).Count -gt 0
  $wouldChange = @($remove).Count -gt 0 -or @($add).Count -gt 0
  $badShape = @($warnings).Count -gt 0
  if($hasDelete -or $wouldChange -or $badShape){ [ordered]@{ number=$item.number; is_pr=[bool]$item.pull_request; title=[string]$item.title; url=[string]$item.html_url; original_labels=$orig; proposed_labels=$proposed; remove_labels=$remove; add_labels=$add; warnings=$warnings } }
}
$summary = [ordered]@{ schema='dcoir.issue197.label_migration_dry_run.v1'; repo=$repo; request_id=$requestId; collected_utc=(Get-Date).ToUniversalTime().ToString('yyyy-MM-ddTHH:mm:ssZ'); mode='dry-run-no-mutations'; existing_label_count=@($labelNames).Count; create_label_candidates=$createCandidates; rename_plan=$renameMap; final_keep_labels=@($keepLabels | Sort-Object); final_delete_labels=@($deleteLabels | Sort-Object); affected_item_count=@($plans).Count; warning_item_count=@($plans | Where-Object { @($_.warnings).Count -gt 0 }).Count; affected_items=@($plans | Sort-Object is_pr, number) }
$reportDir=Join-Path $repoRoot "chatgpt_staging/status_reports/chatgpt-exec/$requestId"; New-Item -ItemType Directory -Force -Path $reportDir | Out-Null
$jsonPath=Join-Path $reportDir 'label_migration_dry_run.json'; $mdPath=Join-Path $reportDir 'label_migration_dry_run.md'
$summary | ConvertTo-Json -Depth 12 | Out-File -FilePath $jsonPath -Encoding utf8
$lines=@('# Issue #197 Label Migration Dry Run','',"- repo: $repo","- collected_utc: $($summary.collected_utc)",'- mode: dry-run-no-mutations',"- existing_label_count: $($summary.existing_label_count)","- affected_item_count: $($summary.affected_item_count)","- warning_item_count: $($summary.warning_item_count)",'', '## Create label candidates','')
$lines += @($createCandidates | Sort-Object | ForEach-Object { "- $_" })
$lines += @('', '## Rename plan', '')
foreach($k in $renameMap.Keys){ $lines += "- $k -> $($renameMap[$k])" }
$lines += @('', '## Final keep labels', '')
$lines += @($summary.final_keep_labels | ForEach-Object { "- $_" })
$lines += @('', '## Final delete labels', '')
$lines += @($summary.final_delete_labels | ForEach-Object { "- $_" })
$lines += @('', '## Affected issues and PRs', '', '| Item | Kind | Remove | Add | Warnings |', '| ---: | --- | --- | --- | --- |')
foreach($p in $summary.affected_items){ $kind=if($p.is_pr){'PR'}else{'Issue'}; $rm=(@($p.remove_labels) -join ', '); $ad=(@($p.add_labels) -join ', '); $warn=(@($p.warnings) -join '; '); $lines += "| #$($p.number) | $kind | $rm | $ad | $warn |" }
$lines | Out-File -FilePath $mdPath -Encoding utf8
Write-Host "Wrote label migration dry run:"; Write-Host $jsonPath; Write-Host $mdPath
